import sharp from 'sharp';

const MAX_WIDTH = 240;
const MAX_HEIGHT = 360;
const JPEG_QUALITY = 82;

const PLACEHOLDER_THUMBNAIL = Buffer.from(
  '',
  'base64'
);

/**
 * Resize a cover image into a small JPEG suitable for storage in the
 * `comics.cover_thumbnail` BLOB column. Returns the placeholder when the
 * input is empty, malformed, or sharp can't decode it.
 */
export async function generateThumbnail(source: Buffer | null | undefined): Promise<Buffer> {
  if (!source || source.length === 0) return PLACEHOLDER_THUMBNAIL;

  try {
    const encoded = await sharp(source)
      .resize({
        width: MAX_WIDTH,
        height: MAX_HEIGHT,
        fit: 'inside',
        withoutEnlargement: true,
      })
      .jpeg({ quality: JPEG_QUALITY })
      .toBuffer();
    return encoded.length > 0 ? encoded : PLACEHOLDER_THUMBNAIL;
  } catch {
    return PLACEHOLDER_THUMBNAIL;
  }
}
